sp_widget.client_script:
api.controller = function($scope, $timeout) {
    var c = this;
    c.scanning = false;
    c.scannerInstance = null;
    c.lastResult = null;
    c.validating = false;

    c.startScanner = function() {
        if (c.scanning) return;
        c.scanning = true;
        c.lastResult = null;

        $timeout(function() {
            if (typeof Html5Qrcode !== 'undefined') {
                c.scannerInstance = new Html5Qrcode('linq-scanner-view');
                c.scannerInstance.start(
                    { facingMode: 'environment' },
                    { fps: 10, qrbox: { width: 250, height: 250 } },
                    function(decodedText) {
                        // On successful scan
                        c.stopScanner();
                        $scope.$apply(function() {
                            c.validateToken(decodedText);
                        });
                    },
                    function() {
                        // QR code parse error — ignore, keep scanning
                    }
                );
            }
        }, 300);
    };

    c.stopScanner = function() {
        if (c.scannerInstance) {
            c.scannerInstance.stop().then(function() {
                c.scannerInstance.clear();
            }).catch(function() {
                // Ignore stop errors
            });
        }
        c.scanning = false;
    };

    c.validateToken = function(token) {
        c.validating = true;
        c.lastResult = null;
        c.server.get({
            action: 'validate_qr',
            token: token
        }).then(function(r) {
            c.lastResult = r.data.scanResult;
            c.validating = false;
        }, function() {
            c.lastResult = { valid: false, message: 'Network error. Please try again.' };
            c.validating = false;
        });
    };

    c.scanAgain = function() {
        c.lastResult = null;
        c.startScanner();
    };

    // Cleanup on widget destroy
    $scope.$on('$destroy', function() {
        c.stopScanner();
    });
};

sp_widget.css:
.sp-card {
    border: 1px solid $border-tertiary;
    border-radius: $border-radius-large;
    box-shadow: 0 1px 4px rgba($text-color, 0.07);
    background: $background-primary;
    overflow: hidden;
    margin-bottom: 24px;
    max-width: 500px;
    margin-left: auto;
    margin-right: auto;
}
.sp-card-header {
    padding: 16px 24px;
    background: $background-primary;
    border-bottom: 1px solid $border-tertiary;
}
.sp-card-title {
    font-size: $font-size-large;
    font-weight: 600;
    color: $text-color;
    margin: 0;
}
.sp-card-title .glyphicon {
    margin-right: 8px;
    color: $brand-primary;
}
.sp-card-body {
    padding: 24px;
}
.sp-scanner-view {
    width: 100%;
    max-width: 350px;
    margin: 0 auto 16px;
    border-radius: $border-radius-base;
    overflow: hidden;
}
.sp-scanner-controls {
    margin-top: 16px;
}
.sp-validating {
    padding: 32px 0;
}
.sp-validating .glyphicon {
    font-size: 32px;
    color: $brand-primary;
    display: block;
    margin-bottom: 12px;
}
.sp-result {
    padding: 32px 0;
}
.sp-result-icon {
    font-size: 48px;
    display: block;
    margin-bottom: 12px;
}
.sp-result h4 {
    font-size: 22px;
    font-weight: 700;
    margin-bottom: 8px;
}
.sp-result-valid .sp-result-icon,
.sp-result-valid h4 {
    color: $brand-success;
}
.sp-result-invalid .sp-result-icon,
.sp-result-invalid h4 {
    color: $brand-danger;
}
.sp-btn-primary {
    height: 44px;
    padding: 0 20px;
    border-radius: $border-radius-base;
    font-size: $font-size-base;
    font-weight: 500;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    transition: background 0.15s, box-shadow 0.15s;
    cursor: pointer;
    border: none;
    background: $brand-primary;
    color: $btn-primary-color;
    &:hover:not(:disabled) {
        background: $brand-primary-dark;
        box-shadow: 0 2px 8px rgba($brand-primary, 0.3);
        color: $btn-primary-color;
    }
}
.sp-btn-secondary {
    background: $background-primary;
    border: 1px solid $border-tertiary;
    color: $text-color;
    height: 44px;
    padding: 0 20px;
    border-radius: $border-radius-base;
    font-size: $font-size-base;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    &:hover {
        background: $background-secondary;
    }
}
@keyframes sp-spin {
    to { transform: rotate(360deg); }
}
.sp-spin {
    animation: sp-spin 0.8s linear infinite;
}

sp_widget.script:
(function() {
    data.accessDenied = false;
    data.scanResult = null;
    data.errorMsg = '';

    try {
        // Handle QR validation action
        if (input && input.action === 'validate_qr') {
            var helper = new global.LinqQRHelper();
            var result = helper.validateToken(input.token);

            if (result && result.valid) {
                // Insert attendance record
                var attGr = new GlideRecord('x_2097092_linq_attendance');
                attGr.initialize();
                attGr.setValue('event', result.event_id);
                attGr.setValue('registration', result.registration_id);
                attGr.setValue('student', result.student_id);
                attGr.setValue('status', 'present');
                attGr.setValue('scan_timestamp', new GlideDateTime().getValue());
                attGr.setValue('verified_by', gs.getUserID());
                attGr.insert();

                data.scanResult = {
                    valid: true,
                    studentName: result.student_name + '',
                    eventTitle: result.event_title + ''
                };
            } else {
                data.scanResult = {
                    valid: false,
                    message: (result && result.message) ? result.message + '' : 'Invalid or expired QR token.'
                };
            }
            return;
        }

        // Initial load — check access
        var userId = gs.getUserID();
        var memGr = new GlideRecord('x_2097092_linq_club_membership');
        memGr.addQuery('member', userId);
        memGr.addQuery('role', 'IN', 'president,secretary');
        memGr.addQuery('status', 'active');
        memGr.setLimit(1);
        memGr.query();

        if (!memGr.hasNext()) {
            data.accessDenied = true;
            return;
        }
    } catch (e) {
        gs.error('linq-qr-scanner error: ' + e.message);
        data.errorMsg = 'An error occurred.';
    }
})();
